'use client'
import { useState, useEffect, useRef } from 'react'

const CHAR_SRC = 'data:image/png;base64,'

const MESSAGES = [
  'hey! what are you looking for? 👀',
  'videos? ai? games?',
  'your brain is calling',
  'all free, no cap fr',
  'built on a phone btw 📱',
  'good vibes only zone',
  'scroll down bestie',
  'tap me, i dare you',
]

export default function VibeChar() {
  const [msgIdx, setMsgIdx] = useState(0)
  const [msgVisible, setMsgVisible] = useState(true)
  const [wiggle, setWiggle] = useState(false)
  const [excited, setExcited] = useState(false)

  // Message rotation
  useEffect(() => {
    const iv = setInterval(() => {
      setMsgVisible(false)
      setTimeout(() => {
        setMsgIdx(i => (i + 1) % MESSAGES.length)
        setMsgVisible(true)
      }, 280)
    }, 3800)
    return () => clearInterval(iv)
  }, [])

  // Scroll excitement
  useEffect(() => {
    const onScroll = () => setExcited(window.scrollY > 350)
    window.addEventListener('scroll', onScroll, { passive: true })
    return () => window.removeEventListener('scroll', onScroll)
  }, [])

  const handleClick = () => {
    if (wiggle) return
    setWiggle(true)
    setExcited(true)
    setTimeout(() => { setWiggle(false); setExcited(false) }, 700)
  }

  return (
    <div
      onClick={handleClick}
      style={{
        position: 'relative',
        display: 'inline-flex',
        flexDirection: 'column',
        alignItems: 'center',
        cursor: 'pointer',
        userSelect: 'none',
        WebkitTapHighlightColor: 'transparent',
      }}
    >
      <style>{`
        @keyframes charFloat {
          0%,100% { transform: translateY(0px) rotate(-0.5deg); }
          50%      { transform: translateY(-12px) rotate(0.5deg); }
        }
        @keyframes charWiggle {
          0%,100% { transform: rotate(0deg) scale(1); }
          20%     { transform: rotate(-6deg) scale(1.04); }
          40%     { transform: rotate(6deg) scale(0.97); }
          60%     { transform: rotate(-4deg) scale(1.02); }
          80%     { transform: rotate(3deg); }
        }
        @keyframes charExcited {
          0%,100% { transform: translateY(0) rotate(-0.5deg); }
          25%     { transform: translateY(-16px) rotate(-1.5deg); }
          75%     { transform: translateY(-8px) rotate(1deg); }
        }
        @keyframes msgIn {
          from { opacity: 0; transform: translateY(6px) scale(0.93); }
          to   { opacity: 1; transform: translateY(0) scale(1); }
        }
        @keyframes sparkPulse {
          0%,100% { opacity:0.15; transform: scale(0.6) rotate(0deg); }
          50%     { opacity:1;    transform: scale(1.1) rotate(18deg); }
        }
        @keyframes sparkPulse2 {
          0%,100% { opacity:0.1;  transform: scale(0.55) rotate(0deg); }
          60%     { opacity:0.85; transform: scale(1)   rotate(-14deg); }
        }
      `}</style>

      {/* Speech bubble */}
      <div style={{
        background: 'var(--vs-card)',
        border: '1.5px solid var(--vs-border)',
        borderRadius: 14,
        padding: '7px 14px',
        fontSize: 11,
        fontWeight: 600,
        color: 'var(--vs-text)',
        whiteSpace: 'nowrap',
        marginBottom: 8,
        position: 'relative',
        boxShadow: '0 2px 10px rgba(0,0,0,0.07)',
        opacity: msgVisible ? 1 : 0,
        transform: msgVisible ? 'translateY(0) scale(1)' : 'translateY(5px) scale(0.95)',
        transition: 'opacity 0.25s, transform 0.25s',
      }}>
        {MESSAGES[msgIdx]}
        {/* Tail */}
        <div style={{
          position: 'absolute', bottom: -7, left: '50%',
          transform: 'translateX(-50%)',
          width: 0, height: 0,
          borderLeft: '7px solid transparent',
          borderRight: '7px solid transparent',
          borderTop: '7px solid var(--vs-border)',
        }} />
        <div style={{
          position: 'absolute', bottom: -5, left: '50%',
          transform: 'translateX(-50%)',
          width: 0, height: 0,
          borderLeft: '6px solid transparent',
          borderRight: '6px solid transparent',
          borderTop: '6px solid var(--vs-card)',
        }} />
      </div>

      {/* Character + sparkles wrapper */}
      <div style={{ position: 'relative', width: 180, height: 210 }}>
        {/* Sparkles */}
        <span style={{
          position: 'absolute', top: 16, right: 6,
          fontSize: 13, color: 'var(--vs-accent)',
          animation: 'sparkPulse 2.4s ease-in-out infinite',
          animationDelay: '0.3s', lineHeight: 1,
        }}>✦</span>
        <span style={{
          position: 'absolute', top: 58, left: 2,
          fontSize: 9, color: 'var(--vs-accent2)',
          animation: 'sparkPulse2 3s ease-in-out infinite',
          animationDelay: '1.1s', lineHeight: 1,
        }}>✦</span>
        <span style={{
          position: 'absolute', bottom: 30, right: 4,
          fontSize: 8, color: 'var(--vs-accent)',
          animation: 'sparkPulse 2.8s ease-in-out infinite',
          animationDelay: '0.8s', lineHeight: 1,
        }}>✦</span>

        {/* Character image */}
        <img
          src={CHAR_SRC}
          alt="VibeScape mascot"
          width={180}
          height={210}
          style={{
            display: 'block',
            objectFit: 'contain',
            width: '100%',
            height: '100%',
            animation: wiggle
              ? 'charWiggle 0.6s ease'
              : excited
              ? 'charExcited 1.8s ease-in-out infinite'
              : 'charFloat 3.2s ease-in-out infinite',
            transformOrigin: 'center bottom',
            filter: 'drop-shadow(0 8px 16px rgba(0,0,0,0.12))',
            imageRendering: 'auto',
          }}
          draggable={false}
        />
      </div>

      {/* Tap hint */}
      <p style={{
        fontSize: 9,
        color: 'var(--vs-text-sub)',
        marginTop: 3,
        opacity: 0.5,
      }}>tap me ✦</p>
    </div>
  )
}
